#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y;
    bool operator<(const node&b)const
    {
        return x*b.y>b.x*y;
    }
}a[200010];
long long n;
long long ans;
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        string str;
        cin>>str;
        long long l=str.length();
        for(long long j=0;j<l;j++)
        {
            if(str[j]=='X')
            {
                a[i].x++;
            }
            else
            {
                long long temp=str[j]-'0';
                a[i].y+=temp;
                ans+=a[i].x*temp;
            }
        }
    }
    sort(a+1,a+1+n);
    long long sum=0;
    for(long long i=1;i<=n;i++)
    {
        ans+=sum*a[i].y;
        sum+=a[i].x;
    }
    printf("%lld",ans);
    return 0;
}
